import{_ as p,o as a,c as e,j as r,a as t,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const A=JSON.parse('{"title":"音击战士训练","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/5.通用类/音击战士训练.md","filePath":"4.资源分区/1.血统与训练/5.通用类/音击战士训练.md"}'),n={name:"4.资源分区/1.血统与训练/5.通用类/音击战士训练.md"};function d(o,b,_,l,c,i){return a(),e("div",null,[...b[0]||(b[0]=[r("h1",{id:"音击战士训练",tabindex:"-1"},[t("音击战士训练 "),r("a",{class:"header-anchor",href:"#音击战士训练","aria-label":'Permalink to "音击战士训练"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风028")])])],-1),s('<h1 id="音击战士训练-1" tabindex="-1">音击战士训练 <a class="header-anchor" href="#音击战士训练-1" aria-label="Permalink to &quot;音击战士训练&quot;">​</a></h1><p>【音击战士】训练<br> 在某个时空的日本，存在一种与古代传说中的妖怪相仿的谜样生物【魔化魍】，它们以人类为食而攻击人类，<br> 【魔化魍】有着强大怪异的肉体和超自然能力，并且难以消灭，只有敲击一种特殊的矿石【鬼石】，发出清澈之音才能有效对其造成杀伤<br> 为了生存，也为了守护重要的人们，逐渐有一些猛士拿起镶嵌【鬼石】的武器与【魔化魍】对抗，<br> 猛士的肉体也在日复一日的锻炼与战斗中蜕变，最终诞生的，便是以清澈之音退治妖魔的【音击战士】</p><p>由于【魔化魍】多半自深山老林中出现，而【音击战士】为避免牵连到普通人也会选择避世<br> 因此在漫长的历史过去后，【音击战士】已经淡出了大众视野，甚至不为大多数人所知，化作传闻怪谈的一部分<br> 人们也更习惯称呼他们为另一种妖怪的名字——【鬼】</p><p>D级：【鬼之弟子】<br> D+600<br> 【音击战士】代代以师徒关系传承，选择此训练后，你将拜某位【音击战士】为师，在对方的指导下坚持锻炼，日益精进<br> 你获得【修行之路】特性，你可以额外支付分数或xp来获取【音击之道】特性</p><p>【修行之路】：<br> 与强大怪异的【魔化魍】，需要你有坚韧的意志，灵活的技巧，强健的身躯。为此，你需要经历异常严苛的修行。<br> 只有将心、技、体全部修炼至协调完美，才能被称为是独当一面的【鬼】，从而得到师傅的认可<br> 根据你在心、技、体三方面的锻炼阶段，你获得【心之修行】、【技之修行】、【体之修行】三种锻炼效果：</p><p>①【心之修行】：<br> 以属性+技能+专业计算你的意志豁免DP（不计算附加成功）<br> 当这个数值在【16及以下】/【17至27】/【28至38】/【39至49】/【50及以上】时，<br> 你的【心】修炼等级为D/C/B/A/S，每场影片结束后，你的意志豁免对应获得1/2/3/4/5点修行加值</p><p>②【技之修行】：<br> 以属性+技能+专业计算你的反射豁免DP（不计算附加成功）<br> 当这个数值在【16及以下】/【17至27】/【28至38】/【39至49】/【50及以上】时，<br> 你的【技】修炼等级为D/C/B/A/S，每场影片结束后，你的反射豁免对应获得1/2/3/4/5点修行加值</p><p>③【体之修行】：<br> 以属性+技能+专业计算你的强韧豁免DP（不计算附加成功）<br> 当这个数值在【16及以下】/【17至27】/【28至38】/【39至49】/【50及以上】时，<br> 你的【体】修炼等级为D/C/B/A/S，每场影片结束后，你的强韧豁免对应获得1/2/3/4/5点修行加值</p><p>【音击之道】：<br> 该特性可在购买本训练D级之后，额外支付1000分或4XP获得。<br> 若你这么做，你需要在购买本训练C级之后，额外支付D+1000或12XP获得完整效果，此时你如同购买了一项D级技艺一样正常获得自由属性。该特性可重复购买，每次购买选择不同的替代效果。</p><p>在【音击战士】的战斗中，既要依靠常规武器的攻击，也要依靠音乐的力量<br> 久而久之，【音击战士】掌握了以战斗术演奏音乐，或以音乐施展战斗术的方法</p><p>购买时从以下效果中选择一项，选定后不可更改<br> ①以一种你已有的【武技/射击：任意武器+对应辅助专业（学识）】代替一种【表达：任意乐器+辅助专业：乐理学（学识）】进行检定</p><p>②以一种你已有的【表达：任意乐器+辅助专业：乐理学（学识）】代替一种【武技/射击：任意武器+对应辅助专业（学识）】进行检定</p><p>D级时，你仅能替代对应的辅助专业，C级后，你可以在此基础上将技能+专业完整替代。</p><p>以此方法实现的技能+专业代替需要有画风描述，讲述你是以何种形式来用某种武器代替某种乐器，或以何种形式来用某种乐器代替某种武器。<br> 例如：<br> 1.以锤子、棍棒、剑柄，盾牌等存在硬质可敲击部位的武器，代替敲奏类乐器，如鼓、沙锤，或反过来。<br> 2.以存在中空腔体的武器，如枪械，代替吹奏类乐器，如号子、笛子，或反过来。<br> 3.以包含，或改装增加了线状结构的武器，如弓弩，代替弹奏类乐器，如吉他、贝斯，或反过来。<br> 4.以及其他合理的画风描述。</p><p>C级：【鬼之震变】<br> C+1200<br> 终于，经过漫长的修炼，你的实力与心性得到了师傅的认可，从他手中接过了【鬼】的称号与武器<br> 训练提升至此等级后，你获得【猛士的支援】、【变身】特性，并具有【XX鬼】的称号（由你自行决定并以这种格式命名）</p><p>【猛士的支援】：<br> 【音击战士】说到底是保护人类的职业，不可能没有与人交集<br> 而那些被【鬼】所拯救过的平民为了报答恩情，组织起了名为【猛士】的团体，他们以莲花为标志，专门负责为【鬼】提供生活和战斗上的支援<br> 现在你也是被他们正式认可的英雄，他们也会不遗余力地为你提供帮助</p><p>当你在影片中且处于人类阵营时，你会获得一个能查到过往经历的身份，并附带有相关的记忆<br> 该身份为【猛士】组织所支持的战士，可以无偿从【猛士】组织中获取优渥生活阶级的资金（一般对应小老板、落魄贵族、小有名气的歌手等），不附带人际关系，会按照影片情况安排住所或出行工具。对于不同世界背景的影片，ST可根据需要修改该背景身份。<br> 这是一个C级信息来源的【背景身份】效果。</p><p>【变身】：<br> 选择一种你已有的乐器，或可替代乐器的武器，根据其乐器种类（敲奏类、吹奏类、弹奏类），<br> 你获得对应的【变身音叉】/【变身鬼笛】/【变身鬼弦】。<br> 以一个整轮动作，你敲击/吹响/拨动对应的变身道具，并将其平放于面前，震动的音波逐渐笼罩你的全身<br> 你的额头会浮现出一张小型的恶鬼面庞，代表着你体内的鬼神之力被唤醒<br> 随后，与你下文选择的属性相同的元素会汇聚在你身上，形成【鬼】的姿态。</p><p>通过以上的步骤，你变身成为【鬼】的姿态，这使你获得【鬼的武器】、【鬼的身躯】特性，持续一个场景：</p><p>①【鬼的武器】：<br> 工欲善其事，必先利其器。为了让你能充分发挥战斗力，【猛士】组织无偿为你最擅长的武器/乐器进行了镶嵌【鬼石】的改造<br> 选择一种你已有的武器/乐器，在变身状态中，你使用此武器/乐器进行攻击检定时，根据你从下方选择的【流派】获得不同属性加成<br> 选定的【流派】不能更改，对应的武器/乐器强化可在幕间转移至其他同种类的武器/乐器中</p><p>1.【雷之流派】：<br> 激发【鬼石】的雷电之力，一般使用弹奏类乐器的流派。<br> 选择此流派后，在变身状态中，你使用【鬼石】改造的武器/乐器发起的攻击附加【1】点不可豁免的【麻痹】不良点数，可叠加。</p><p>2.【火之流派】<br> 激发【鬼石】的火炎之力，一般使用敲奏类乐器的流派。<br> 选择此流派后，在变身状态中，你使用【鬼石】改造的武器/乐器发起的攻击附加【1】点不可豁免的【燃烧】不良点数，可叠加。</p><p>3.【风之流派】<br> 激发【鬼石】的旋风之力，一般使用吹奏类乐器的流派。<br> 选择此流派后，在变身状态中，你使用【鬼石】改造的武器/乐器发起的攻击附加【1】点不可豁免的【眩晕】不良点数，可叠加。</p><p>4.【雪之流派】<br> 激发【鬼石】的冰雪之力，几乎失传的流派。<br> 选择此流派后，在变身状态中，你使用【鬼石】改造的武器/乐器发起的攻击附加【1】点不可豁免的【冻结】不良点数，可叠加。</p><p>②【鬼的身躯】：<br> 你获得等同于你的【心】、【技】、【体】三种修炼等级（每个分类d1c2b3a4s5）之和的【天生防御】。<br> 这是你持之以恒的修行的成果，全部是汗水和努力。</p><p>B级：【鬼之极限】<br> B+2400<br> 【魔化魍】是一种会随着季节变迁，在某些特殊时期大量诞生和活跃的怪物，大约在每年的夏季，【魔化魍】的数量和强度都会大大提升<br> 为此，【音击战士】都有在夏季到来前将自己的身躯锻炼至极限，以承载大量的元素能量，使自己进入更强大的极限化状态<br> 训练提升至此等级后，你在使用【鬼的武器】中选择的检定进行攻击时，获得【8加骰】特性。取代C级的【变身】，你获得【极限变身】、【堕落变身】特性</p><p>【极限变身】：<br> 将体内的属性之气磨练到极致后，以一个整轮动作，你可以变身为更强大的极限化状态，持续一个场景<br> 该状态下，根据你选择的流派属性，对应的元素之力布满你的全身，使你外表的颜色也变为对应元素的颜色，<br> 这个姿态称之为【XX鬼·（某种颜色）】，由你自行决定并以这种格式命名<br> 例如，选择火之流派的响鬼，在该状态下称为【响鬼·红】</p><p>该姿态下，你继承C级变身中获得的【鬼的武器】特性，【鬼的身躯】提供的天生防御翻倍处理。</p><p>【堕落变身】：<br> 并非所有人都能接纳有着强大力量和恐怖外表的【鬼】。<br> 事实上，不止一次有孤独战斗的【鬼】因为被人类排斥而感到痛苦，最终在仇恨中堕落成为【魔化魍】。<br> 而除此之外，怨念、悲痛、愁苦等各种负面情绪都有催化【鬼】成为【魔化魍】的可能<br> 尤其是当变身者与【鬼】之力日益结合紧密的时候，责任的重担会令堕落的风险越来越大<br> 鬼之极限，既是力量的极限，也是心灵的极限。</p><p>现在，在你已经使用整轮动作进行【极限变身】的基础上，你可以主动选择拥抱内心的堕落情绪，使用自由动作动作变身为近似【魔化魍】的存在，持续一个场景。<br> 在该状态下，额头处的鬼面极度扩大，象征着内心被恶意占据，你获得【堕落边缘】特性，同时可以从【妖魔之力】、【妖魔之躯】中选择一种获得，选择后无法改变。</p><p>①【妖魔之力】：你以【鬼的武器】中对应的攻击方法进行检定时，附带A级影响心灵来源的【扼魂】效果影响，目标需要以意志豁免。</p><p>②【妖魔之躯】：每轮一次，根据你在【鬼的武器】中对应的攻击方法的类别（近战或远程中的一种），你受到相同类别的攻击伤害减少至原来的一半。</p><p>③【堕落边缘】：每次受到伤害时，你必须以意志豁免对抗受到的实际伤害数值。若豁免失败，则你立即陷入A级影响心灵来源的【混乱】状态，将会无差别攻击在你周围由近及远的所有目标，直至陷入昏迷或无意识状态，或场景结束。</p><p>特别的，使用【堕落变身】具有无法变回人类的危险可能，每场影片中你至多施展一次【堕落变身】。</p><p>A级：【鬼之装甲】<br> A+5800<br> 特别的，本级训练也可以在购买了8种【光盘兽】后，将【光盘兽】作为素材消耗，再支付1800分的调整费，从而兑换获得。<br> 注：本级训练只允许在B级的基础上，一次性支付A+5800或将全部8种【光盘兽】消耗再支付1800分兑换。购买的【光盘兽】不足8种的情况下不允许替代兑换。</p><p>自古以来，各流派都认为【极限变身】就是【鬼】能达到的最强状态，想要更强，只有拥抱【魔化魍】的力量<br> 但是随着时代发展而变强的，还有支援着【鬼】的一般民众，即猛士们<br> 他们开发出了各式的支援装备，为了报恩而贡献出自己的力量<br> 终于，当无数微小的力量汇聚到一起，怨念、悲痛、愁苦等各种负面情绪被人与人之间的羁绊压制，更加强大的【装甲变身】诞生了</p><p>你的变身道具与你在【鬼的武器】中选择的武器/乐器融为一体，化为【音击增幅（你的武器种类）·装甲声（你的武器种类）】（由你自行按照格式命名）<br> 例如，选择【剑】作为【鬼的武器】，则化为【音击增幅剑·装甲声刃】<br> 此变化不会对你的武器造成影响，仅是你可以用此武器进行【装甲变身】</p><p>替代B级的【极限变身】与【堕落变身】，你能以一个标准动作进行【装甲变身】<br> 象征着他人对你的支援的8种【光盘兽】武装到你的身上，形成坚不可摧的装甲<br> 【装甲变身】：<br> 继承【极限变身】与【堕落变身】的全部效果，并且不再具有【堕落边缘】特性。</p><p>此外，【光盘兽】已经完全与你的身体结合，即使不变身，你常态下也能获得以下能力：<br> 【茜鹰的羽翼】：你获得等同于你基础移动速度的飞行能力，机动性完美。<br> 【琉璃狼的奔袭】：你的移动速度提升80m<br> 【绿大猿的巧手】：你使用【鬼的武器】中选择的武器/乐器进行对应的攻击检定时，可以重新投掷一次出目，二次结果取优计算。<br> 【黄檗蟹的甲壳】：你获得基于天生防御的【坚韧】特性，并且免疫接触攻击。<br> 【浅葱鹫的锐目】：你获得基于视觉的【透视】。<br> 【黄赤狮子的霸吼】：你使用【鬼的武器】中选择的武器/乐器进行对应的攻击检定时，附带【余波】效果。<br> 【青磁蛙的潜游】：你获得等同于你的移动速度的游泳速度，附带水下呼吸能力。<br> 【钝色蛇的隐匿】：你获得B级特异本质的【反侦测】效果。</p><p>【音击战士相关技艺】<br> 在漫长的传承中，【音击战士】也总结各流派特性，研究出了各种独特的技艺<br> 以下每种技艺必须在你至少有对应的训练等级后才可购买</p><p>【鬼斗术】<br> C+1500<br> 以一个标准动作，你使用在【鬼的武器】中选择的武器/乐器对射程范围内的目标发起一次攻击<br> 此次攻击提升7L武器伤害，并根据你在【鬼的武器】中选择的流派，附加1点不可豁免的【麻痹】/【燃烧】/【眩晕】/【冻结】异常点数<br> 此外，根据你的武器与流派不同，该技艺可以有不同的命名，由你自行决定<br> 例如以剑刃为武器，风为流派，可称为【鬼斗术·旋风刃】；以拳为武器，雷为流派，可称为【鬼斗术·雷击拳】等</p><p>【鬼法术】<br> C+1000<br> 以一个标准动作，你张开口部，向前方20m的锥形范围内喷吐出与你选择的流派属性相对应的元素。<br> 以【决心+学识：鬼法术】进行检定，具有【法破】特性，对范围内的所有敌方目标造成伤害，反射豁免。<br> 此外，根据你的流派不同，对应伤害性质为【电击】/【火焰】/【音波】/【冻寒】，并且该技艺可以有不同的命名，由你自行决定<br> 例如火之流派为【鬼法术·鬼火】、雷之流派为【鬼法术·鬼雷】等，由你自行命名。</p><p>【音击术·蓄击】<br> B+4000<br> 可由【鬼斗术】或【鬼法术】差价升级得来。<br> 以一个标准动作蓄力，再以一个标准动作，使用在【鬼的武器】中选择的武器/乐器进行一次攻击检定。<br> 在你使用第一个标准动作蓄力后，视作你已经使用了“在【鬼的武器】中选择的武器/乐器对应的技能+专业”进行了格挡，该格挡效果至多持续一轮，直到你下一次释放攻击为止。你最迟在下一轮中使用标准动作释放攻击，若没有，视作蓄力被打断，格挡效果也消失。</p><p>此次攻击提升7L武器伤害，范围提升至以你为中心，半径为原本射程（20米）的圆形，对范围内所有的敌人进行攻击。<br> 此次攻击具有【法破】效果，使用此技艺时你的武器视作具有【能量武器】效果。<br> 此外，根据你在【鬼的武器】中选择的流派，此次攻击附带等同伤害出目的【麻痹】/【眩晕】/【冻结】异常点数，强韧豁免，或转化为等量的【燃烧】异常点数，反射豁免。</p><p>根据你的武器与流派不同，该技艺可以有不同的命名，由你自行决定。<br> 例如，选择锤为武器，雪为流派，可称为【音击打·一击怒涛】；选择刀刃为武器，雷为流派，可称为【音击斩·雷电斩震】等。</p><p>【音击术·连击】<br> B+2500<br> 可由【鬼斗术】或【鬼法术】差价升级得来。<br> 以一个标准动作，你使用在【鬼的武器】中选择的武器/乐器进行一次攻击检定，此次攻击具有【接触攻击】特性<br> 命中时，根据你在【鬼的武器】中选择的流派，附加3点不可豁免的【麻痹】/【燃烧】/【眩晕】/【冻结】异常点数。</p><p>你在此次检定中至多可以额外支付【本训练等级数（即d1c2b3a4）】点AP，每额外支付1点AP使你此次检定获得3点连击（技艺）加值。<br> 那之后，你可以选择将此次攻击的最终伤害平均拆分为【额外支付的AP数】次攻击检定，即你至多平均拆分为d1c2b3a4次伤害，只需要计算一次防御与减伤相关内容，以及附带的效果。即假设造成12点伤害，A级支付4AP，可以造成12/4=3即4次3伤害，但只需要处理一次相关效果，且这一步骤在最后处理（伤害翻倍等效果先行计算，最后再拆分伤害，因此无法获得任何相关的好处，也不需要计算多次防御和减伤降低拆分后的伤害数值）。</p><p>表现为你用武器死死贴近目标后连续攻击，如使用鼓棒连打/连续拨动琴弦/快速连吹乐器等。<br> 根据你的武器与流派不同，该技艺可以有不同的命名，由你自行决定。<br> 例如，选择锤为武器，火为流派，可称为【音击打·火炎连打】等。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',50)])])}const D=p(n,[["render",d]]);export{A as __pageData,D as default};
